example.code:
# library-chart/Chart.yaml
apiVersion: v2
name: common-helpers
version: 0.1.0
type: library
description: Shared templates and functions for microservices

# library-chart/templates/_helpers.tpl
{{- define "common.name" -}}
{{ default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{- define "common.fullname" -}}
{{ if .Values.fullnameOverride }}{{ .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}{{- else }}{{ .Release.Name }}-{{ include "common.name" . }}{{- end }}
{{- end }}

{{- define "common.labels" -}}
app.kubernetes.io/name: {{ include "common.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

# app-chart/Chart.yaml (dependent)
dependencies:
  - name: common-helpers
    version: 0.1.0
    repository: file://../library-chart

# app-chart/templates/deployment.yaml (uses library)
metadata:
  name: {{ include "common.fullname" . }}
  labels:
    {{- include "common.labels" . | nindent 4 }}

# templates/configmap.yaml apiVersion: v1 kind: ConfigMap metadata: name: {{ include "myapp.fullname" . }}-config data: app.conf: | {{ .Values.appConfig | nindent 4 }}
# templates/deployment.yaml spec: template: metadata: annotations: # Force restart when ConfigMap changes checksum/config: {{ include (print $.Template.BasePath "/configmap.yaml") . | sha256sum }} spec: containers: - name: app volumeMounts: - name: config mountPath: /etc/config volumes: - name: config configMap: name: {{ include "myapp.fullname" . }}-config
# templates/pvc.yaml (resource protection) apiVersion: v1 kind: PersistentVolumeClaim metadata: name: {{ include "myapp.fullname" . }}-data annotations: "helm.sh/resource-policy": keep # survives helm uninstall spec: accessModes: - ReadWriteOnce resources: requests: storage: 10Gi

# templates/deployment.yaml
env:
  - name: DATABASE_HOST
    value: {{ required "database.host is required" .Values.database.host }}

# values.schema.json (IDE validation)
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": ["image", "database"],
  "properties": {
    "image": {
      "type": "object",
      "required": ["repository", "tag"],
      "properties": {
        "repository": { "type": "string" },
        "tag": { "type": "string" }
      }
    },
    "database": {
      "type": "object",
      "required": ["host"],
      "properties": {
        "host": { "type": "string" }
      }
    }
  }
}

library-common/ ├── Chart.yaml # type: library ├── templates/ │ ├── _helpers.tpl # Named templates only │ └── _defaults.tpl # Additional helpers └── README.md
# Chart.yaml apiVersion: v2 name: library-common version: 0.1.0 type: library description: Shared templates for microservices
# templates/_helpers.tpl {{- define "common.fullname" -}} {{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }} {{- end }}
{{- define "common.labels" -}} app: {{ include "common.fullname" . }} version: {{ .Chart.AppVersion }} {{- end }}
# Dependent chart uses library: # Chart.yaml dependencies: - name: library-common version: 0.1.0 repository: "file://../library-common"
# templates/deployment.yaml (uses library) metadata: labels: {{- include "common.labels" . | nindent 4 }}

#!/bin/bash # .github/workflows/helm-validate.yml or CI script set -e
echo "=== 1. Lint ===" helm lint ./mychart --strict
echo "=== 2. Template Output ===" helm template myrelease ./mychart --values values-dev.yaml > /tmp/manifests.yaml echo "Generated $(cat /tmp/manifests.yaml | grep -c ^apiVersion:) manifests"
echo "=== 3. Kubernetes API Validation ===" kubectl apply --dry-run=server -f /tmp/manifests.yaml
echo "=== 4. Install in Test Cluster ===" helm install myapp-ci ./mychart \ --namespace test-${GITHUB_RUN_ID} \ --create-namespace \ --values values-dev.yaml
echo "=== 5. Wait for Readiness ===" kubectl rollout status deployment/myapp -n test-${GITHUB_RUN_ID} --timeout=2m
echo "=== 6. Run Helm Tests ===" helm test myapp-ci --namespace test-${GITHUB_RUN_ID}
echo "=== 7. Integration Tests ===" POD=$(kubectl get pods -n test-${GITHUB_RUN_ID} -l app=myapp -o jsonpath='{.items[0].metadata.name}') kubectl exec -it $POD -n test-${GITHUB_RUN_ID} -- curl http://localhost:8080/health
echo "=== 8. Cleanup ===" helm uninstall myapp-ci --namespace test-${GITHUB_RUN_ID} kubectl delete namespace test-${GITHUB_RUN_ID}
echo "=== All Validation Passed ==="
